class Solution:
    def distanceTraveled(self, mainTank, additionalTank):
        transfers = min((mainTank - 1) // 4, additionalTank)
        return (mainTank + transfers) * 10

solutions.python:
class Solution:
    def distanceTraveled(self, mainTank, additionalTank):
        dist = 0
        while mainTank >= 5:
            mainTank -= 5
            dist += 50
            if additionalTank > 0:
                additionalTank -= 1
                mainTank += 1
        dist += mainTank * 10
        return dist

